"use strict";(globalThis.webpackChunkwebsite=globalThis.webpackChunkwebsite||[]).push([[5507],{5111:(e,t,n)=>{n.r(t),n.d(t,{assets:()=>l,contentTitle:()=>r,default:()=>u,frontMatter:()=>s,metadata:()=>i,toc:()=>d});const i=JSON.parse('{"id":"part1-foundations/the-rsa-prime-solution-suite","title":"The RSA Prime Solution Suite","description":"The opening block of instruction established that Prime is best understood as a continuously evolving suite of applications layered on top of RSA Authentication Manager (AM) and the RSA Cloud Authentication Service (CAS), built and extended by a small dedicated team in direct response to customer gaps. As the trainer put it, engineering did not support many of these capabilities from day one; the Prime team saw the gaps because they work closely with customers, and built the bridges themselves. In several cases (for example, user synchronization between AM and CAS) capabilities pioneered in Prime were later absorbed into the core product.","source":"@site/prime-training/part1-foundations/3-the-rsa-prime-solution-suite.md","sourceDirName":"part1-foundations","slug":"/part1-foundations/the-rsa-prime-solution-suite","permalink":"/rsapsdocumentation/docs/part1-foundations/the-rsa-prime-solution-suite","draft":false,"unlisted":false,"tags":[],"version":"current","sidebarPosition":3,"frontMatter":{"title":"The RSA Prime Solution Suite","sidebar_position":3},"sidebar":"docsSidebar","previous":{"title":"Session Logistics, Participants, and Structure","permalink":"/rsapsdocumentation/docs/part1-foundations/session-logistics-participants-and-structure"},"next":{"title":"PrimeKit Packaging and the Technology Stack","permalink":"/rsapsdocumentation/docs/part1-foundations/primekit-packaging-and-the-technology-stack"}}');var o=n(4848),a=n(8453);const s={title:"The RSA Prime Solution Suite",sidebar_position:3},r="The RSA Prime Solution Suite",l={},d=[{value:"Core Web Applications",id:"core-web-applications",level:2},{value:"Bulk Administration Tools",id:"bulk-administration-tools",level:2},{value:"Additional Suite Components",id:"additional-suite-components",level:2},{value:"Why Prime Exists",id:"why-prime-exists",level:2}];function c(e){const t={a:"a",h1:"h1",h2:"h2",header:"header",li:"li",p:"p",ul:"ul",...(0,a.R)(),...e.components};return(0,o.jsxs)(o.Fragment,{children:[(0,o.jsx)(t.header,{children:(0,o.jsx)(t.h1,{id:"the-rsa-prime-solution-suite",children:"The RSA Prime Solution Suite"})}),"\n",(0,o.jsx)(t.p,{children:"The opening block of instruction established that Prime is best understood as a continuously evolving suite of applications layered on top of RSA Authentication Manager (AM) and the RSA Cloud Authentication Service (CAS), built and extended by a small dedicated team in direct response to customer gaps. As the trainer put it, engineering did not support many of these capabilities from day one; the Prime team saw the gaps because they work closely with customers, and built the bridges themselves. In several cases (for example, user synchronization between AM and CAS) capabilities pioneered in Prime were later absorbed into the core product."}),"\n",(0,o.jsx)(t.h2,{id:"core-web-applications",children:"Core Web Applications"}),"\n",(0,o.jsxs)(t.ul,{children:["\n",(0,o.jsx)(t.li,{children:"MS / AMS (the REST services engine). The core of Prime. AMS exposes a REST interface that talks to both Authentication Manager and the Cloud Authentication Service, and acts as the integration hub for every other Prime component. All admin operations \u2014 user lookup, unlock, enable/disable, token assignment, security domain creation \u2014 flow through AMS REST APIs. AMS also serves as the synchronization bridge between AM and CAS (e.g., auto-creating a user in one product when it exists only in the other)."}),"\n",(0,o.jsx)(t.li,{children:"SSP (Self-Service Portal). The end-user-facing web portal for credential enrollment, token management, and (in customized deployments) on-demand password generation. Supports internal and internet-facing deployments with independently configurable authentication methods and branding."}),"\n",(0,o.jsx)(t.li,{children:"HTAP (Help Desk / Admin Portal). The delegated administration portal for help desk staff, referenced throughout the day alongside MS and SSP as the third core Tomcat application (ports and startup scripts are provisioned for all three)."}),"\n"]}),"\n",(0,o.jsx)(t.h2,{id:"bulk-administration-tools",children:"Bulk Administration Tools"}),"\n",(0,o.jsxs)(t.ul,{children:["\n",(0,o.jsx)(t.li,{children:"Bulk Invitation Tool \u2014 sends enrollment invitations to multiple users at once."}),"\n",(0,o.jsx)(t.li,{children:"Bulk Enrollment Tool \u2014 the CAS analogue of bulk invitation; sends enrollment links for cloud authentication users. Scheduled for hands-on coverage on Day 2."}),"\n",(0,o.jsxs)(t.li,{children:["Bulk Update Tool \u2014 a recently developed, rapidly evolving Java command-line utility for bulk operations: assigning aliases, rotating user passwords in Active Directory (with WPI cache synchronization), and \u2014 added on customer request \u2014 deleting admin roles via CSV input, which the core product cannot do. This tool received its own dedicated deep-dive session (Part 2, ",(0,o.jsx)(t.a,{href:"/rsapsdocumentation/docs/part1-foundations/ssp-configuration-and-authentication-methods",children:"Section 12"})," of this document)."]}),"\n"]}),"\n",(0,o.jsx)(t.h2,{id:"additional-suite-components",children:"Additional Suite Components"}),"\n",(0,o.jsxs)(t.ul,{children:["\n",(0,o.jsx)(t.li,{children:"PCAP (Prime Central Authentication Portal). An on-premises identity provider for customers who cannot use the Cloud Authentication Service as an IdP \u2014 typically state/government or restricted environments. PCAP currently supports SAML and OIDC, uses Authentication Manager as the source of truth, presents a configurable multi-method login portal, and provides a user application launcher ('My Page'-style) that displays applications based on group membership."}),"\n",(0,o.jsx)(t.li,{children:"VTS (Virtual Token Service). A small desktop application that generates token codes for users who cannot carry a software or hardware token \u2014 particularly useful for VDI/VDA-based Windows environments. Functionally, an authenticator that runs as a local desktop service."}),"\n",(0,o.jsx)(t.li,{children:"ENS (Expiry / Event Notification Service). A command-line scheduler that taps the Authentication Manager database via report downloads and emails users about expiring tokens, expiring PINs, and other lifecycle events, using brandable and customizable email templates."}),"\n"]}),"\n",(0,o.jsx)(t.h2,{id:"why-prime-exists",children:"Why Prime Exists"}),"\n",(0,o.jsx)(t.p,{children:"The 'Why Prime' slide consolidated the rationale threaded through the morning: the core products leave operational gaps (self-service, delegated help desk, bulk operations, AM\u2194CAS synchronization, on-prem IdP, notification automation), and Prime fills them faster than core engineering can because the Prime team ships configuration-driven features without UI overhead. The suite framing also carries a commercial implication that surfaced later in the field discussion: customers frequently buy Prime for one narrow use case (e.g., WPI password rotation) while remaining unaware of the rest of the suite \u2014 creating natural expansion conversations for PS consultants who can demonstrate adjacent capabilities once the primary use case is delivered."})]})}function u(e={}){const{wrapper:t}={...(0,a.R)(),...e.components};return t?(0,o.jsx)(t,{...e,children:(0,o.jsx)(c,{...e})}):c(e)}},8453:(e,t,n)=>{n.d(t,{R:()=>s,x:()=>r});var i=n(6540);const o={},a=i.createContext(o);function s(e){const t=i.useContext(a);return i.useMemo(function(){return"function"==typeof e?e(t):{...t,...e}},[t,e])}function r(e){let t;return t=e.disableParentContext?"function"==typeof e.components?e.components(o):e.components||o:s(e.components),i.createElement(a.Provider,{value:t},e.children)}}}]);